import java.io.*;
import java.nio.file.*;
import java.security.MessageDigest;
import java.util.*;
import java.util.stream.Collectors;

public class minigit {
    private static final String MINIGIT_DIR = ".minigit";
    private static final String OBJECTS_DIR = MINIGIT_DIR + "/objects";
    private static final String INDEX_FILE = MINIGIT_DIR + "/index";
    private static final String HEAD_FILE = MINIGIT_DIR + "/HEAD";
    private static final String REFS_DIR = MINIGIT_DIR + "/refs";
    private static final String MASTER_REF = REFS_DIR + "/master";

    public static void main(String[] args) throws Exception {
        if (args.length == 0) {
            System.exit(0);
        }
        String command = args[0];
        switch (command) {
            case "init":
                init();
                break;
            case "add":
                if (args.length < 2) {
                    System.exit(1);
                }
                add(args[1]);
                break;
            case "commit":
                if (args.length < 2) {
                    System.exit(1);
                }
                commit(args[1]);
                break;
            case "log":
                log();
                break;
            default:
                System.exit(1);
        }
    }

    private static void init() throws Exception {
        File dir = new File(MINIGIT_DIR);
        if (dir.exists()) {
            System.exit(1);
        }
        new File(OBJECTS_DIR).mkdirs();
        new File(REFS_DIR).mkdirs();
        Files.write(Paths.get(HEAD_FILE), "ref: refs/master\n".getBytes());
    }

    private static void add(String filename) throws Exception {
        File f = new File(filename);
        if (!f.exists()) {
            System.exit(1);
        }
        String content = new String(Files.readAllBytes(f.toPath()));
        String blob = "blob " + content.length() + "\0" + content;
        String hash = sha1(blob);
        Path objectPath = Paths.get(OBJECTS_DIR, hash);
        Files.write(objectPath, blob.getBytes());
        List<String> index = new ArrayList<>();
        File indexFile = new File(INDEX_FILE);
        if (indexFile.exists()) {
            index.addAll(Files.readAllLines(indexFile.toPath()));
        }
        String entry = hash + " " + filename;
        index.removeIf(line -> line.endsWith(" " + filename));
        index.add(entry);
        Files.write(indexFile.toPath(), String.join("\n", index).getBytes());
    }

    private static void commit(String message) throws Exception {
        File indexFile = new File(INDEX_FILE);
        if (!indexFile.exists()) {
            System.exit(1);
        }
        List<String> indexLines = Files.readAllLines(indexFile.toPath());
        StringBuilder treeBuilder = new StringBuilder();
        for (String line : indexLines) {
            String[] parts = line.split(" ", 2);
            treeBuilder.append("100644 ").append(parts[1]).append("\0").append(parts[0]).append("\n");
        }
        String treeContent = treeBuilder.toString();
        String tree = "tree " + treeContent.length() + "\0" + treeContent;
        String treeHash = sha1(tree);
        Path treePath = Paths.get(OBJECTS_DIR, treeHash);
        Files.write(treePath, tree.getBytes());

        String parent = "";
        File masterFile = new File(MASTER_REF);
        if (masterFile.exists()) {
            parent = new String(Files.readAllBytes(masterFile.toPath())).trim();
        }

        StringBuilder commitBuilder = new StringBuilder();
        commitBuilder.append("tree ").append(treeHash).append("\n");
        if (!parent.isEmpty()) {
            commitBuilder.append("parent ").append(parent).append("\n");
        }
        commitBuilder.append("author minigit <minigit@example.com> ").append(System.currentTimeMillis() / 1000).append(" +0000\n");
        commitBuilder.append("committer minigit <minigit@example.com> ").append(System.currentTimeMillis() / 1000).append(" +0000\n");
        commitBuilder.append("\n").append(message).append("\n");
        String commitContent = commitBuilder.toString();
        String commit = "commit " + commitContent.length() + "\0" + commitContent;
        String commitHash = sha1(commit);
        Path commitPath = Paths.get(OBJECTS_DIR, commitHash);
        Files.write(commitPath, commit.getBytes());

        Files.write(masterFile.toPath(), commitHash.getBytes());
        indexFile.delete();
    }

    private static void log() throws Exception {
        File masterFile = new File(MASTER_REF);
        if (!masterFile.exists()) {
            System.exit(0);
        }
        String commit = new String(Files.readAllBytes(masterFile.toPath())).trim();
        while (!commit.isEmpty()) {
            Path commitPath = Paths.get(OBJECTS_DIR, commit);
            if (!Files.exists(commitPath)) {
                break;
            }
            String data = new String(Files.readAllBytes(commitPath));
            int nullPos = data.indexOf('\0');
            String content = data.substring(nullPos + 1);
            String[] lines = content.split("\n");
            String message = "";
            boolean inMessage = false;
            for (String line : lines) {
                if (line.isEmpty()) {
                    inMessage = true;
                    continue;
                }
                if (inMessage) {
                    message = line;
                    break;
                }
            }
            System.out.println("commit " + commit);
            System.out.println("    " + message);
            String parent = "";
            for (String line : lines) {
                if (line.startsWith("parent ")) {
                    parent = line.substring(7);
                    break;
                }
            }
            if (parent.isEmpty()) {
                break;
            }
            commit = parent;
        }
    }

    private static String sha1(String input) throws Exception {
        MessageDigest md = MessageDigest.getInstance("SHA-1");
        byte[] digest = md.digest(input.getBytes());
        StringBuilder sb = new StringBuilder();
        for (byte b : digest) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}
